*/

'use strict';

// MODULES //

var setReadOnly = require( '@stdlib/utils/define-nonenumerable-read-only-property' );
var rangeBy = require( './range_by.js' );
var ndarray = require( './ndarray.js' );


// MAIN //

setReadOnly( rangeBy, 'ndarray', ndarray );


// EXPORTS //

module.exports = rangeBy;

