'use strict';

// MODULES //

var tape = require( 'tape' );
var floor = require( '@stdlib/math/base/special/floor' );
var isnan = require( '@stdlib/math/base/assert/is-nan' );
var isPositiveZero = require( '@stdlib/math/base/assert/is-positive-zero' );
var Float64Array = require( '@stdlib/array/float64' );
var rangeBy = require( './../lib/range_by.js' );


// FUNCTIONS //

function accessor( v ) {
	if ( v === void 0 ) {
		return;
	}
	return v * 2.0;
}


// TESTS //

tape( 'main export is a function', function test( t ) {
	t.ok( true, __filename );
	t.strictEqual( typeof rangeBy, 'function', 'main export is a function' );
	t.end();
});

tape( 'the function has an arity of 5', function test( t ) {
	t.strictEqual( rangeBy.length, 5, 'has expected arity' );
	t.end();
});

tape( 'the function calculates the range of a strided array via a callback function', function test( t ) {
	var x;
	var v;

	x = [ 1.0, -2.0, -4.0, 5.0, 0.0, 3.0 ];
	v = rangeBy( x.length, x, 1, accessor );
	t.strictEqual( v, 18.0, 'returns expected value' );

	x = [ -4.0, -5.0 ];
	v = rangeBy( x.length, x, 1, accessor );
	t.strictEqual( v, 2.0, 'returns expected value' );

	x = [ -0.0, 0.0, -0.0 ];
	v = rangeBy( x.length, x, 1, accessor );
	t.strictEqual( isPositiveZero( v ), true, 'returns expected value' );

	x = [ NaN ];
	v = rangeBy( x.length, x, 1, accessor );
	t.strictEqual( isnan( v ), true, 'returns expected value' );

	x = [ NaN, NaN ];
	v = rangeBy( x.length, x, 1, accessor );
	t.strictEqual( isnan( v ), true, 'returns expected value' );

	x = new Array( 5 ); // sparse array
	v = rangeBy( x.length, x, 1, accessor );
	t.strictEqual( isnan( v ), true, 'returns expected value' );

	x = new Array( 5 ); // sparse array
	x[ 2 ] = 1.0;
	v = rangeBy( x.length, x, 1, accessor );
	t.strictEqual( v, 0.0, 'returns expected value' );

	t.end();
});

tape( 'if provided an `N` parameter less than or equal to `0`, the function returns `NaN`', function test( t ) {
	var x;
	var v;

	x = [ 1.0, -2.0, -4.0, 5.0, 3.0 ];

	v = rangeBy( 0, x, 1, accessor );
	t.strictEqual( isnan( v ), true, 'returns expected value' );

	v = rangeBy( -1, x, 1, accessor );
	t.strictEqual( isnan( v ), true, 'returns expected value' );

	t.end();
});

tape( 'if provided an `N` parameter equal to `1`, the function returns `0`', function test( t ) {
	var x;
	var v;

	x = [ 1.0, -2.0, -4.0, 5.0, 3.0 ];

	v = rangeBy( 1, x, 1, accessor );
	t.strictEqual( v, 0.0, 'returns expected value' );

	x = new Array( 1 ); // sparse array

	v = rangeBy( 1, x, 1, accessor );
	t.strictEqual( isnan( v ), true, 'returns expected value' );

	t.end();
});

tape( 'the function supports a `stride` parameter', function test( t ) {
	var N;
	var x;
	var v;

	x = [
		1.0,  // 0
		2.0,
		2.0,  // 1
		-7.0,
		-2.0, // 2
		3.0,
		4.0,  // 3
		2.0
	];

	N = floor( x.length / 2 );
	v = rangeBy( N, x, 2, accessor );

	t.strictEqual( v, 12.0, 'returns expected value' );
	t.end();
});

tape( 'the function supports a negative `stride` parameter', function test( t ) {
	var N;
	var x;
	var v;

	x = [
		1.0,  // 3
		2.0,
		2.0,  // 2
		-7.0,
		-2.0, // 1
		3.0,
		4.0,  // 0
